import { Router } from "express";
import * as controller from "../controllers/produtosController.js";
import { requireAuth } from "../middlewares/auth.js";
import { requireRole } from "../middlewares/requireRole.js";
import { validate } from "../middlewares/validate.js";
import { createProdutoSchema, updateProdutoSchema } from "../schemas/produto.schema.js";
const router = Router();
router.get("/", controller.listar);
router.get("/:id", controller.obter);
router.post("/", requireAuth, requireRole("ADMIN", "STAFF"), validate(createProdutoSchema), controller.criar);
router.put("/:id", requireAuth, requireRole("ADMIN", "STAFF"), validate(updateProdutoSchema), controller.atualizar);
router.delete("/:id", requireAuth, requireRole("ADMIN", "STAFF"), controller.remover);
export default router;
